    pub fn setColorsDark(self: GuiContext) void { self._b.setColorsDarkFn(); }
    pub fn setStyleFloat(self: GuiContext, name: []const u8, value: f64) void {
        self._b.setStyleFloatFn(name, @floatCast(value));
